import { Fragment, type JSX } from 'react';
import { useIntl } from 'react-intl';

import { formatDate } from '@dynatrace-sdk/units';

import { useAnnotationsTooltipFormatter } from './hooks/useAnnotationsTooltipFormatter.js';
import { getSymbol } from './utils/get-symbol.js';
import { Divider } from '../../../../../../layouts/divider/Divider.js';
import type { TruncationMode } from '../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { Footer } from '../../../overlay-tooltip/components/Footer.js';
import { Header } from '../../../overlay-tooltip/components/header/Header.js';
import { SeriesItem } from '../../../overlay-tooltip/components/series/SeriesItem.js';
import { ExternalConfigContext } from '../../../overlay-tooltip/contexts/ExternalConfigContext.js';
import { OVERLAY_TOOLTIP_MESSAGES } from '../../../overlay-tooltip/messages.js';
import { useSelector } from '../../../overlay-tooltip/selectors.js';
import {
  annotationsGroupsScrollContainer,
  divider,
  seriesGridContainer,
} from '../../../overlay-tooltip/tooltip.sty.js';
import type {
  ExternalConfig,
  HeaderData,
} from '../../../overlay-tooltip/types.js';
import { useAnnotationsActions } from '../../hooks/useAnnotationsActions.js';
import type {
  AnnotationsActionsPayload,
  AnnotationsMarkerGroup,
} from '../../types/annotations.js';
import { deserializeMarkerRange } from '../../utils/serialize-marker-range.js';

const BASE_ACTIONS_CONFIG: ExternalConfig['defaultActionsConfig'] = new Map([
  ['name', { field: 'valueLabel' }],
]);

const buildExternalConfig = (
  truncationMode: TruncationMode,
): ExternalConfig => ({
  seriesHeader: null,
  displayHeaderDivider: false,
  symbolPosition: 'left',
  truncationMode,
  defaultActionsConfig: BASE_ACTIONS_CONFIG,
  variant: 'single',
});

type AnnotationsDefaultTooltipContentProps = {
  data: AnnotationsMarkerGroup[];
  tooltipType: 'time' | 'numerical';
  truncationMode: TruncationMode;
  maxLines: number;
};

const X_VALUE_LABEL = 'X-value';

/**
 * Default tooltip content for AnnotationsChart, rendered through
 * OverlayTooltip primitives. Supports multiple (Header, Series) pairs for
 * collided marker groups.
 *
 * @internal
 */
export const AnnotationsDefaultTooltipContent = (
  props: AnnotationsDefaultTooltipContentProps,
) => {
  const { data, tooltipType, truncationMode, maxLines } = props;
  const formatter = useAnnotationsTooltipFormatter();
  const annotationsActions = useAnnotationsActions();
  const config = buildExternalConfig(truncationMode);
  const intl = useIntl();
  const unpinnedPlaceholderText = intl.formatMessage(
    OVERLAY_TOOLTIP_MESSAGES.unpinnedPlaceholderMessage,
  );
  // Direct subscription needed: passed as stable legacyTemplate prop, so no parent re-render reaches this fiber when pinned changes.
  const pinned = useSelector((state) => state.pinned);

  return (
    <ExternalConfigContext.Provider value={config}>
      <div className={annotationsGroupsScrollContainer}>
        {data.map((annotationGroup, groupIndex) => {
          const [from, to] = deserializeMarkerRange(annotationGroup.key);
          const isRange = to > from;

          let header1: HeaderData;
          let showRangeDuration = false;
          let duration: string | undefined;

          if (tooltipType === 'numerical' && isRange) {
            header1 = [formatter(from), formatter(to)] as HeaderData;
            duration = String(Math.abs(to - from));
          } else if (tooltipType === 'numerical') {
            header1 = formatter(from);
          } else if (isRange) {
            header1 = [new Date(from), new Date(to)] as HeaderData;
            showRangeDuration = true;
          } else {
            header1 = formatDate(new Date(from), {
              day: '2-digit',
              month: 'short',
              year: 'numeric',
              hour: '2-digit',
              minute: '2-digit',
            });
          }

          return (
            <Fragment key={annotationGroup.key}>
              {groupIndex > 0 && (
                <Divider orientation="horizontal" className={divider} />
              )}
              <Header
                header1={header1}
                label={X_VALUE_LABEL}
                showRangeDuration1={showRangeDuration}
                duration1={duration}
                maxLines={maxLines}
              />
              <div className={seriesGridContainer}>
                {annotationGroup.markers.map((marker) => {
                  const icon = getSymbol(marker) as JSX.Element;
                  const {
                    id,
                    symbol,
                    title: markerTitle,
                    description: markerDescription,
                    start,
                    end,
                    color,
                    priority,
                    hidden: markerHidden,
                    ...extraFields
                  } = marker;
                  const payload: AnnotationsActionsPayload = {
                    ...extraFields,
                    start,
                    end,
                    title: markerTitle,
                    description: markerDescription,
                    symbol,
                  };
                  const actions = annotationsActions?.(payload);
                  return (
                    <SeriesItem
                      key={id}
                      name={markerTitle ?? ''}
                      description={markerDescription}
                      value=""
                      icon={icon}
                      multiLine={maxLines > 1}
                      maxLines={maxLines}
                      actions={actions ? () => actions : undefined}
                    />
                  );
                })}
              </div>
            </Fragment>
          );
        })}
      </div>
      {!pinned && (
        <Footer
          actions={[]}
          unpinnedPlaceholderText={unpinnedPlaceholderText}
        />
      )}
    </ExternalConfigContext.Provider>
  );
};

AnnotationsDefaultTooltipContent.displayName =
  'AnnotationsDefaultTooltipContent';
